<template>
  <div class="publish-page">
    <aside class="panel terminal-panel">
      <div class="panel-title"><div><h2>信息终端</h2></div><el-icon><Monitor /></el-icon></div>
      <div class="summary"><span>在线 <b class="online">{{ onlineCount }}</b></span><span>离线 <b class="offline">{{ terminals.length - onlineCount }}</b></span><span>设备数 <b>{{ terminals.length }}</b></span></div>
      <div class="select-all"><el-checkbox v-model="allSelected" :indeterminate="someSelected" @change="toggleAll">全选在线终端</el-checkbox><span>{{ terminals.length }} 台</span></div>
      <div class="terminal-list"><div v-for="building in buildingTree" :key="building.name" class="tree-building"><button type="button" class="building-head" @click="toggleBuilding(building.name)"><el-icon><ArrowDown v-if="building.open" /><ArrowRight v-else /></el-icon><el-icon><OfficeBuilding /></el-icon><strong>{{ building.name }}</strong><small>{{ building.terminals.length }} 台</small></button><div v-if="building.open" class="tree-children"><label v-for="terminal in building.terminals" :key="terminal.id" class="terminal-item" :class="{ selected: terminal.selected, offline: terminal.status === 'offline' }"><el-checkbox v-model="terminal.selected" :disabled="terminal.status === 'offline'" /><span class="status-dot" :class="terminal.status" /><strong>{{ terminal.name }}</strong><em>{{ terminal.status === 'online' ? '在线' : '离线' }}</em></label></div></div></div>
      <footer><el-button type="primary" :icon="Promotion" @click="openComposer">信息发布</el-button><span>仅支持在线终端</span></footer>
    </aside>

    <main class="map-canvas"><img :src="mapImage" alt="园区平面图" /><div class="map-wash" /><div class="map-filter"><el-radio-group v-model="mapFilter" size="small"><el-radio-button value="all">全部</el-radio-button><el-radio-button value="online">在线</el-radio-button><el-radio-button value="offline">离线</el-radio-button></el-radio-group></div><button v-for="terminal in visibleTerminals" :key="terminal.id" class="marker" :class="terminal.status" :style="{ left: `${terminal.left}%`, top: `${terminal.top}%` }" @click="activeTerminal = terminal"><span class="pulse" /><el-icon><Monitor /></el-icon><article v-if="activeTerminal?.id === terminal.id" @click.stop><header><span class="status-dot" :class="terminal.status" /><strong>{{ terminal.name }}</strong><el-button text :icon="Close" @click="activeTerminal = null" /></header><p>编号：{{ terminal.id }}</p><p>当前状态：<b :class="terminal.status">{{ terminal.status === 'online' ? '在线' : '离线' }}</b></p><el-button v-if="terminal.status === 'online'" type="primary" size="small" :icon="Promotion" @click="selectFromMap(terminal)">选择发布</el-button></article></button><div class="map-legend"><span><i class="online" />在线 {{ onlineCount }}</span><span><i class="offline" />离线 {{ terminals.length - onlineCount }}</span></div></main>

    <aside class="panel monitor-panel">
      <template v-if="!composerVisible"><div class="panel-title"><div><h2>发布状态监控</h2><span>实时查看信息发布任务</span></div><el-icon><DataAnalysis /></el-icon></div><div class="monitor-summary"><div><b>{{ tasks.length }}</b><span>发布中任务</span></div><el-button type="danger" plain size="small" :disabled="selectedTasks.length === 0" @click="stopSelected">停播{{ selectedTasks.length ? `（${selectedTasks.length}）` : '' }}</el-button></div><div v-if="tasks.length" class="task-list"><article v-for="task in tasks" :key="task.id" class="task"><div class="task-head"><el-checkbox v-model="task.selected" /><strong>{{ task.target }}</strong><small>{{ task.deadline }} 截止</small></div><div class="task-content" :class="{ previewable: task.type !== '文字' }" @click="task.type !== '文字' && previewTask(task)"><span class="media-icon" :class="task.type">{{ task.type === '文字' ? 'T' : task.type === '图片' ? 'IMG' : '▶' }}</span><el-tooltip :content="task.summary" placement="top"><span>{{ task.summary }}</span></el-tooltip></div></article></div><div v-else class="empty"><el-icon><Monitor /></el-icon><strong>暂无发布中的信息</strong><span>选择左侧终端并发布信息后，将在这里实时展示</span></div></template>
      <section v-else class="composer"><header><div><h2>信息发布配置</h2><span>向 {{ selectedTerminals.length }} 台终端发布内容</span></div><el-button text :icon="Close" @click="composerVisible = false" /></header><el-form label-position="top" class="composer-form"><el-form-item label="媒体类型"><el-tabs v-model="mediaType" stretch><el-tab-pane label="文字信息" name="文字" /><el-tab-pane label="图片展示" name="图片" /><el-tab-pane label="视频播放" name="视频" /></el-tabs></el-form-item><el-form-item v-if="mediaType === '文字'" label="发布内容" required><el-input v-model="textContent" type="textarea" :rows="8" maxlength="200" show-word-limit placeholder="请输入需要发布的应急信息" /></el-form-item><el-form-item v-else :label="`${mediaType}素材`" required><div class="upload-box" @click="!uploadedFile && fileInput?.click()"><input ref="fileInput" type="file" accept=".png,.jpg,.jpeg,.mp4" hidden @change="handleFile" /><template v-if="uploadedFile"><span class="file-badge">{{ mediaType }}</span><span class="file-name">{{ uploadedFile.name }}</span><el-button text type="danger" size="small" @click.stop="clearFile">移除</el-button></template><template v-else><el-icon><UploadFilled /></el-icon><b>点击上传{{ mediaType }}素材</b><small>支持 PNG / JPG / MP4，单个文件不超过 50MB</small></template></div></el-form-item><el-form-item label="截止播放时间" required><el-date-picker v-model="deadline" type="datetime" value-format="YYYY-MM-DD HH:mm" format="YYYY-MM-DD HH:mm" placeholder="请选择截止播放时间" style="width:100%" /></el-form-item></el-form><footer><el-button @click="composerVisible = false">取消</el-button><el-button type="primary" :disabled="!canPublish" @click="publish">确认发布</el-button></footer></section>
    </aside>
    <el-dialog v-model="previewVisible" :title="`${previewingTask?.type || ''}预览`" width="520px" destroy-on-close><div class="preview-box"><img v-if="previewingTask?.type === '图片' && previewingTask.previewUrl" :src="previewingTask.previewUrl" :alt="previewingTask.summary" /><video v-else-if="previewingTask?.type === '视频' && previewingTask.previewUrl" :src="previewingTask.previewUrl" controls /><div v-else><el-icon><Monitor /></el-icon><p>{{ previewingTask?.summary }}</p><small>当前为原型预览，素材未提供可播放地址</small></div></div></el-dialog>
  </div>
</template>

<script setup lang="ts">
import { computed, ref } from 'vue'
import { ArrowDown, ArrowRight, Close, DataAnalysis, Monitor, OfficeBuilding, Promotion, UploadFilled } from '@element-plus/icons-vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import mapImage from '@/map.png'

type Status = 'online' | 'offline'
type Terminal = { id: string; name: string; building: string; status: Status; left: number; top: number; selected: boolean }
type Task = { id: number; target: string; type: string; summary: string; deadline: string; selected: boolean; previewUrl?: string }
const terminals = ref<Terminal[]>([{ id: 'CT-1F-ES-01', name: '1楼电梯屏', building: 'CT楼', status: 'online', left: 29, top: 38, selected: false }, { id: 'CT-2F-ES-01', name: '2楼电梯屏', building: 'CT楼', status: 'online', left: 45, top: 29, selected: false }, { id: 'FF-1F-ES-01', name: '1楼电梯屏', building: 'FF楼', status: 'online', left: 62, top: 52, selected: false }, { id: 'FF-2F-ES-01', name: '2楼电梯屏', building: 'FF楼', status: 'offline', left: 52, top: 72, selected: false }])
const tasks = ref<Task[]>([{ id: 1, target: '1楼电梯（CT楼）', type: '文字', summary: '请尽快撤离危险区域，听从现场工作人员指引，避免引发踩踏，注意个人生命安全', deadline: '2026-07-15 18:30', selected: false }, { id: 2, target: '1楼电梯（FF楼）', type: '图片', summary: 'emergency-guide.png', deadline: '2026-07-15 17:00', selected: false }])
const activeTerminal = ref<Terminal | null>(null); const mapFilter = ref<'all' | Status>('all'); const composerVisible = ref(false); const mediaType = ref('文字'); const textContent = ref(''); const uploadedFile = ref<File | null>(null); const deadline = ref(''); const fileInput = ref<HTMLInputElement | null>(null); const previewVisible = ref(false); const previewingTask = ref<Task | null>(null); const buildingOpen = ref<Record<string, boolean>>({ 'CT楼': true, 'FF楼': true })
const onlineCount = computed(() => terminals.value.filter((item) => item.status === 'online').length); const visibleTerminals = computed(() => terminals.value.filter((item) => mapFilter.value === 'all' || item.status === mapFilter.value)); const selectedTerminals = computed(() => terminals.value.filter((item) => item.selected)); const selectedTasks = computed(() => tasks.value.filter((item) => item.selected)); const buildingTree = computed(() => ['CT楼', 'FF楼'].map((name) => ({ name, open: buildingOpen.value[name], terminals: terminals.value.filter((item) => item.building === name) }))); const allSelected = computed({ get: () => selectedTerminals.value.length === onlineCount.value, set: () => undefined }); const someSelected = computed(() => selectedTerminals.value.length > 0 && selectedTerminals.value.length < onlineCount.value); const canPublish = computed(() => Boolean(deadline.value && (mediaType.value === '文字' ? textContent.value.trim() : uploadedFile.value)))
function toggleAll(value: string | number | boolean) { terminals.value.forEach((item) => { if (item.status === 'online') item.selected = Boolean(value) }) }
function toggleBuilding(name: string) { buildingOpen.value[name] = !buildingOpen.value[name] }
function selectFromMap(terminal: Terminal) { terminal.selected = true; activeTerminal.value = null; ElMessage.success(`已选择 ${terminal.name}`) }
function defaultDeadline() { const date = new Date(Date.now() + 12 * 60 * 60 * 1000); const pad = (value: number) => String(value).padStart(2, '0'); return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}` }
function openComposer() { if (!selectedTerminals.value.length) { ElMessage.warning('请先选择至少一台在线信息终端'); return }; composerVisible.value = true; mediaType.value = '文字'; textContent.value = ''; uploadedFile.value = null; deadline.value = defaultDeadline() }
function handleFile(event: Event) { uploadedFile.value = (event.target as HTMLInputElement).files?.[0] || null }
function clearFile() { uploadedFile.value = null; if (fileInput.value) fileInput.value.value = '' }
function publish() { if (!canPublish.value) return; const summary = mediaType.value === '文字' ? textContent.value : uploadedFile.value?.name || ''; const previewUrl = mediaType.value !== '文字' && uploadedFile.value ? URL.createObjectURL(uploadedFile.value) : undefined; const created = selectedTerminals.value.map((terminal, index) => ({ id: Date.now() + index, target: `${terminal.name.replace('屏', '')}（${terminal.building}）`, type: mediaType.value, summary, deadline: deadline.value, selected: false, previewUrl })); tasks.value.unshift(...created); selectedTerminals.value.forEach((item) => { item.selected = false }); composerVisible.value = false; ElMessage.success(`已向 ${created.length} 台终端发布信息`) }
function previewTask(task: Task) { previewingTask.value = task; previewVisible.value = true }
function stopSelected() { const count = selectedTasks.value.length; if (!count) return; ElMessageBox.confirm(`确定停止已选的 ${count} 个发布任务吗？`, '停播确认', { confirmButtonText: '确认停播', cancelButtonText: '取消', type: 'warning' }).then(() => { tasks.value = tasks.value.filter((item) => !item.selected); ElMessage.success(`已停止 ${count} 个信息播放任务`) }).catch(() => undefined) }
</script>

<style lang="scss" scoped>
