er{padding:14px;border-top:1px solid #edf0f5}.terminal-panel footer .el-button{width:100%}.terminal-panel footer span{display:block;margin-top:8px;color:#a8b1bf;text-align:center;font-size:10px}.map-canvas{position:absolute;inset:0;overflow:hidden}.map-canvas>img{width:100%;height:100%;object-fit:cover;filter:saturate(.66) contrast(.94)}.map-wash{position:absolute;inset:0;background:rgba(220,236,222,.12)}.marker{position:absolute;z-index:3;display:grid;place-items:center;width:30px;height:30px;padding:0;transform:translate(-50%,-50%);border:3px solid #fff;border-radius:50%;color:#fff;box-shadow:0 2px 7px rgba(32,54,74,.3);cursor:pointer}.marker.online{background:#20ad82}.marker.offline{background:#e85e66}.pulse{position:absolute;inset:-6px;border-radius:50%;background:inherit;opacity:.3;animation:pulse 2s infinite}.marker article{position:absolute;top:40px;left:50%;width:205px;padding:12px;transform:translateX(-50%);border:1px solid #e1e8f0;border-radius:8px;background:#fff;color:#53647b;box-shadow:0 8px 22px rgba(29,49,78,.18);text-align:left}.marker article header{display:flex;align-items:center;gap:7px}.marker article header strong{flex:1;font-size:12px}.marker article p{margin:8px 0;color:#8c99aa;font-size:10px}.marker article b.online{color:#20ad84}.marker article b.offline{color:#e5686d}.map-legend{position:absolute;right:24px;bottom:20px;display:flex;gap:15px;padding:8px 12px;border-radius:6px;background:rgba(255,255,255,.88);color:#69788c;font-size:10px}.map-legend i{display:inline-block;width:7px;height:7px;margin-right:5px;border-radius:50%}.map-legend .online{background:#20ad82}.map-legend .offline{background:#e85e66}.monitor-panel{position:absolute;z-index:20;top:16px;right:16px;bottom:16px;display:flex;width:360px;flex-direction:column;overflow:hidden}.monitor-summary{display:flex;align-items:center;justify-content:space-between;padding:13px 17px;border-block:1px solid #edf0f5}.monitor-summary b{display:block;color:#4b77df;font-size:25px}.monitor-summary span{color:#9da8b7;font-size:10px}.task-list{overflow:auto;padding:8px 12px}.task{margin-bottom:7px;padding:9px 10px;border:1px solid #e9edf3;border-radius:7px;background:#fbfcfe}.task-head{display:flex;align-items:center;gap:7px;min-width:0}.task-head strong{min-width:0;flex:1;overflow:hidden;color:#3e526c;font-size:12px;text-overflow:ellipsis;white-space:nowrap}.task-head small{flex:none;color:#9ea9b7;font-size:9px}.task-content{display:flex;align-items:center;gap:6px;min-width:0;margin-top:7px;color:#728198;font-size:11px}.task-content.previewable{cursor:pointer}.task-content span:last-child{min-width:0;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.media-icon{display:grid;place-items:center;flex:none;width:21px;height:21px;border-radius:4px;color:#fff;background:#6587dc;font-size:8px;font-weight:700}.media-icon.图片{background:#a875d2}.media-icon.视频{background:#e48b59}.empty{display:flex;flex:1;align-items:center;justify-content:center;flex-direction:column;gap:8px;padding:40px;color:#9ca8b7;text-align:center}.empty .el-icon{font-size:28px}.empty strong{color:#748298;font-size:13px}.empty span{font-size:10px}.composer{display:flex;height:100%;flex-direction:column}.composer header{display:flex;align-items:flex-start;justify-content:space-between;padding:18px;border-bottom:1px solid #edf0f5}.composer-form{flex:1;overflow:auto;padding:18px}.upload-box{display:flex;align-items:center;justify-content:center;min-height:180px;gap:8px;flex-direction:column;width:100%;border:1px dashed #cbd6e5;border-radius:8px;color:#9aa7b7;cursor:pointer}.upload-box .el-icon{font-size:28px;color:#7392dc}.upload-box b{color:#667890;font-size:12px}.upload-box small{font-size:10px}.file-badge{padding:8px 6px;border-radius:4px;color:#fff;background:#738fda;font-size:10px}.file-name{max-width:180px;overflow:hidden;color:#53657c;text-overflow:ellipsis;white-space:nowrap;font-size:11px}.composer footer{display:flex;justify-content:flex-end;gap:10px;padding:14px 18px;border-top:1px solid #edf0f5}.preview-box{display:flex;align-items:center;justify-content:center;min-height:260px;padding:10px;background:#f5f7fa;text-align:center}.preview-box img,.preview-box video{display:block;max-width:100%;max-height:460px;object-fit:contain}.preview-box .el-icon{font-size:36px;color:#7892d1}@keyframes pulse{0%,100%{transform:scale(.7);opacity:.18}50%{transform:scale(1.1);opacity:.42}}@media(max-width:900px){.terminal-panel{top:12px;bottom:auto;left:12px;width:280px;max-height:44%}.monitor-panel{top:calc(44% + 26px);right:12px;bottom:12px;width:330px}}@media(max-width:600px){.terminal-panel{right:12px;width:auto;max-height:40%}.monitor-panel{top:calc(40% + 78px);left:12px;width:auto}.map-legend{right:12px;bottom:12px}}
.map-filter{position:absolute;z-index:5;top:14px;left:305px;padding:5px;border:1px solid rgba(225,231,239,.9);border-radius:6px;background:rgba(255,255,255,.9);box-shadow:0 3px 12px rgba(45,62,83,.1)}@media(max-width:900px){.map-filter{top:calc(44% + 24px);left:12px}}@media(max-width:600px){.map-filter{top:calc(40% + 16px);left:12px}}
</style>
